/**
 * @brief Retrieves the current system timestamp in seconds.
 * @details Uses std::chrono::steady_clock to obtain a monotonic timestamp.
 *          Returns the time in seconds since an unspecified epoch.
 * @return Current timestamp in seconds as uint32_t.
 * @retval >0 Valid timestamp value.
 * @throws None.
 * @note Internal helper function for ProbeApp lifecycle timing.
 */
static uint32_t GetTimestampSec() noexcept
{
    const auto now = std::chrono::steady_clock::now();
    const auto secSinceEpoch = std::chrono::duration_cast<std::chrono::seconds>(
        now.time_since_epoch());
    return static_cast<uint32_t>(secSinceEpoch.count());
}

/**
 * @brief Retrieves the current system timestamp in milliseconds.
 * @details Uses std::chrono::steady_clock to obtain a monotonic timestamp.
 *          Returns the time in milliseconds since an unspecified epoch.
 * @return Current timestamp in milliseconds as uint64_t.
 * @retval >0 Valid timestamp value.
 * @throws None.
 * @note Internal helper function for Run loop cycle timing.
 */
static uint64_t GetTimestampMs() noexcept
{
    const auto now = std::chrono::steady_clock::now();
    const auto msSinceEpoch = std::chrono::duration_cast<std::chrono::milliseconds>(
        now.time_since_epoch());
    return static_cast<uint64_t>(msSinceEpoch.count());
}

