    /* Step 2: Mark application as running */
    isRunning_ = true;

    /* Step 3: Capture startup reference timestamp */
    startupTimeSec_ = GetTimestampSec();

    /* Step 4: Initiate SOME/IP service discovery with DAQ */
    /* isDaqCommEstablished remains false until session confirmed in Run */
